// Three leads, each with THREE JSON keys: id, name, email.
// This shape is fine for almost every n8n node — but it will trip up
// any node that requires single-key input.

return [
  { json: { id: 1, name: "Acme Corp",         email: "founder@acme.test" } },
  { json: { id: 2, name: "Globex Industries", email: "ops@globex.test"   } },
  { json: { id: 3, name: "Initech Systems",   email: "it@initech.test"   } }
];

// ─────────────────────────────────────────────────────────────
// SIMULATED single-key validator.
//
// This is what the following nodes do internally:
//   - Execute Sub-Workflow Trigger (single-key mode)
//   - AI Agent / Tools nodes (LangChain expects a single 'input' key)
//   - Aggregate node in 'Aggregate Individual Fields' mode
//     without a field specified
//
// They check Object.keys(item.json).length and throw if it's not 1.
// We simulate that here so the repro is self-contained.
//
// HOW THE FIX LOOKS:
//
//   Generate 3 Multi-Field Leads   →   Set (reshape)   →   Validator
//        (3 keys per item)             (1 key: 'data')      (passes)
//
//   Set node config (Manual Mapping, in Run Once for Each Item):
//     Field name:  data
//     Field type:  Object
//     Field value: ={{ $json }}
//
//   After that, each item is { json: { data: { id, name, email } } } —
//   one top-level key, exactly what the validator wants.
// ─────────────────────────────────────────────────────────────

const items = $input.all();

for (const item of items) {
  const keys = Object.keys(item.json);
  if (keys.length !== 1) {
    throw new Error(
      `Input values have ${keys.length} keys, you must specify an input key or pass only 1 key as input`
    );
  }
}

return items;
